#include "controller.h"

static controller_output_t controller_make_safe_output(void)
{
    controller_output_t output = {
        .compressor_on = false,
        .vent_open = true,
        .state = CONTROLLER_STATE_SAFE_VENT,
        .state_name = CONTROLLER_STATE_SAFE_VENT_NAME,
        .changed = false,
        .timed_out = false,
    };
    return output;
}

static bool controller_sensor_is_fresh(uint32_t now_ms, uint32_t last_ms)
{
    return (uint32_t) (now_ms - last_ms) <= CONTROLLER_SENSOR_TIMEOUT_MS;
}

static bool controller_has_stale_sensor(const controller_t *controller, uint32_t now_ms)
{
    if (controller == NULL) {
        return false;
    }

    if (controller->has_valid_pressure && !controller_sensor_is_fresh(now_ms, controller->last_pressure_ms)) {
        return true;
    }
    if (controller->has_valid_door && !controller_sensor_is_fresh(now_ms, controller->last_door_ms)) {
        return true;
    }
    return false;
}

static void controller_apply_safe_state(controller_output_t *output)
{
    if (output == NULL) {
        return;
    }

    output->compressor_on = false;
    output->vent_open = true;
    output->state = CONTROLLER_STATE_SAFE_VENT;
    output->state_name = CONTROLLER_STATE_SAFE_VENT_NAME;
}

static void controller_apply_pressure_policy(controller_t *controller, controller_output_t *output)
{
    if ((controller == NULL) || (output == NULL)) {
        return;
    }

    if (!controller->has_valid_door || !controller->has_valid_pressure) {
        controller_apply_safe_state(output);
        return;
    }

    if (controller->door_closed) {
        if (controller->last_pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
            output->compressor_on = true;
            output->vent_open = false;
            output->state = CONTROLLER_STATE_PRESSURIZING;
            output->state_name = CONTROLLER_STATE_PRESSURIZING_NAME;
        } else if (controller->last_pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
            output->compressor_on = false;
            output->vent_open = true;
            output->state = CONTROLLER_STATE_RELIEVING;
            output->state_name = CONTROLLER_STATE_RELIEVING_NAME;
        } else {
            output->state = CONTROLLER_STATE_HOLDING;
            output->state_name = CONTROLLER_STATE_HOLDING_NAME;
        }
        return;
    }

    controller_apply_safe_state(output);
}

void controller_init(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller->compressor_on = false;
    controller->vent_open = true;
    controller->state = CONTROLLER_STATE_SAFE_VENT;
    controller->has_valid_pressure = false;
    controller->last_pressure_kpa = 0;
    controller->last_pressure_ms = 0U;
    controller->has_valid_door = false;
    controller->door_closed = false;
    controller->last_door_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output;
    bool had_previous_output;
    bool stale_fault = false;

    if (controller == NULL) {
        return controller_make_safe_output();
    }

    output = (controller_output_t) {
        .compressor_on = controller->compressor_on,
        .vent_open = controller->vent_open,
        .state = controller->state,
        .state_name = controller_state_name(controller->state),
        .changed = false,
        .timed_out = false,
    };

    had_previous_output = (output.compressor_on != false) || (output.vent_open != true) || (output.state != CONTROLLER_STATE_SAFE_VENT);

    switch (input.kind) {
    case CONTROLLER_INPUT_PRESSURE:
        controller->has_valid_pressure = true;
        controller->last_pressure_kpa = input.pressure_kpa;
        controller->last_pressure_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_DOOR_OPEN:
        controller->has_valid_door = true;
        controller->door_closed = false;
        controller->last_door_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_DOOR_CLOSED:
        controller->has_valid_door = true;
        controller->door_closed = true;
        controller->last_door_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        controller_apply_safe_state(&output);
        output.timed_out = true;
        break;
    case CONTROLLER_INPUT_INVALID_PRESSURE:
    case CONTROLLER_INPUT_INVALID_DOOR:
        controller_apply_safe_state(&output);
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        break;
    }

    if (input.kind == CONTROLLER_INPUT_NONE) {
        stale_fault = controller_has_stale_sensor(controller, input.now_ms);
        if (stale_fault) {
            controller_apply_safe_state(&output);
            output.timed_out = true;
        }
    } else if ((input.kind != CONTROLLER_INPUT_SENSOR_TIMEOUT) &&
               (input.kind != CONTROLLER_INPUT_INVALID_PRESSURE) &&
               (input.kind != CONTROLLER_INPUT_INVALID_DOOR)) {
        stale_fault = controller_has_stale_sensor(controller, input.now_ms);
        if (stale_fault) {
            controller_apply_safe_state(&output);
            output.timed_out = true;
        } else {
            controller_apply_pressure_policy(controller, &output);
        }
    }

    if (output.state == CONTROLLER_STATE_PRESSURIZING) {
        output.compressor_on = true;
        output.vent_open = false;
    } else if (output.state == CONTROLLER_STATE_RELIEVING) {
        output.compressor_on = false;
        output.vent_open = true;
    } else if (output.state == CONTROLLER_STATE_SAFE_VENT) {
